projectData.globalCSS:
/* RapidFlow Plumbing template */
body { margin: 0; font-family: 'Segoe UI', system-ui, sans-serif; background: var(--color-page-bg, #f3f7fb); color: var(--color-text-dark, #13293d); }
* { box-sizing: border-box; }
a { transition: opacity .2s ease, transform .2s ease; }
a:hover { opacity: 0.92; }
section { position: relative; }
.rf-badge { display: inline-block; padding: 7px 12px; border-radius: 999px; background: rgba(255,255,255,0.14); border: 1px solid rgba(255,255,255,0.18); font-size: 12px; letter-spacing: .08em; text-transform: uppercase; font-weight: 700; }
.rf-stat-grid { display: grid; gap: 16px; grid-template-columns: repeat(auto-fit, minmax(160px, 1fr)); margin-top: 28px; }
.rf-stat { background: #ffffff; border: 1px solid #d8e4ef; border-radius: 16px; padding: 18px; box-shadow: 0 16px 40px rgba(19,41,61,0.08); }
.rf-stat strong { display: block; font-size: 28px; color: #0b63ce; margin-bottom: 6px; }
.rf-service-grid { display: grid; gap: 18px; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); }
.rf-service-card { background: #ffffff; border: 1px solid #d8e4ef; border-radius: 18px; padding: 24px; box-shadow: 0 18px 50px rgba(19,41,61,0.08); }
.rf-service-card h3 { margin: 0 0 8px; font-size: 20px; }
.rf-service-card p { margin: 0 0 12px; color: #4d657a; line-height: 1.6; }
.rf-service-card ul { margin: 0; padding-left: 18px; color: #4d657a; line-height: 1.6; }
.rf-service-card li + li { margin-top: 6px; }
.rf-highlight { background: linear-gradient(135deg, #0b63ce, #0b8fe5); color: #ffffff; border-radius: 22px; padding: 28px; box-shadow: 0 24px 70px rgba(11,99,206,0.18); }
.rf-highlight h3 { margin: 0 0 10px; font-size: 26px; }
.rf-highlight p { margin: 0; line-height: 1.7; opacity: 0.94; }
.rf-checklist { list-style: none; padding: 0; margin: 18px 0 0; }
.rf-checklist li { margin: 0 0 10px; padding-left: 28px; position: relative; }
.rf-checklist li::before { content: '✓'; position: absolute; left: 0; top: 0; color: #13b16b; font-weight: 800; }
.rf-contact-strip { display: flex; flex-wrap: wrap; gap: 14px; align-items: center; justify-content: space-between; background: #13293d; color: #ffffff; border-radius: 18px; padding: 22px 24px; }
.rf-contact-strip a { color: #ffffff; text-decoration: none; font-weight: 700; }
@media (max-width: 720px) { .rf-contact-strip { align-items: flex-start; } }
